no-unused-vars.example:
// Bad:  const result = fetchData();
//       showLoading();  // result を使わない
// Good: showLoading();

no-else-return.example:
// Bad:  if (err) { return null; } else { return data; }
// Good: if (err) { return null; }
//       return data;

no-nested-ternary.example:
// Bad:  const x = a ? b ? 1 : 2 : 3;
// Good: let x;
//       if (a) { x = b ? 1 : 2; } else { x = 3; }

jsdoc/require-jsdoc.example:
// Bad:  function fetchComments(userId) { ... }
// Good: /**
//        * ユーザーのコメント一覧を取得する
//        * @param {string} userId - ユーザーID
//        * @returns {Promise<Comment[]>} コメント配列
//        */
//       function fetchComments(userId) { ... }

jsdoc/require-param.example:
// Bad:  /**
//        * データを取得する
//        */
// Good: /**
//        * データを取得する
//        * @param {string} endpoint - APIエンドポイント
//        */

jsdoc/require-returns.example:
// Bad:  /** コメントを取得する */
// Good: /**
//        * コメントを取得する
//        * @returns {Promise<Comment[]>} コメント配列
//        */
